module mux_8bit_4to1 (
    input [7:0] data_in_0,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    input [1:0] sel,
    output reg [7:0] y
);

    // Multiplexer logic
    always @(*) begin
        case (sel)
            2'b00: y = data_in_0;
            2'b01: y = b;
            2'b10: y = c;
            2'b11: y = d;
            default: y = 8'b0;
        endcase
    end

endmodule
